const { ApolloServer, gql } = require('apollo-server');
const { buildSchema } = require('graphql');

// Define a simple schema for an invoice
const typeDefs = gql`
  type Invoice {
    id: ID!
    amount: Float!
    date: String!
    description: String
  }

  type Query {
    getInvoiceById(id: ID!): Invoice
  }
`;

// Mock data for invoices
const invoices = [
  { id: '1', amount: 100.50, date: '2023-04-01', description: 'Service A' },
  { id: '2', amount: 200.75, date: '2023-04-02', description: 'Service B' }
];

// Resolver functions
const resolvers = {
  Query: {
    getInvoiceById: (parent, args) => {
      return invoices.find(invoice => invoice.id === args.id);
    },
  },
};

// Create the Apollo Server instance
const server = new ApolloServer({ typeDefs, resolvers });

// Start the server
server.listen().then(({ url }) => {
  console.log(`🚀 Server ready at ${url}`);
});